const now = new Date();
const date = now.toISOString().split('T')[0];
return [{
  json: {
    event: 'checkpoint_generated',
    timestamp: now.toISOString(),
    checkpoint_file: '01_Estrategia/FG_Checkpoint_AUTO_TEST_' + date + '.md',
    summary: 'Prueba manual de checkpoint desde n8n',
    git_status: 'unknown',
    git_branch: 'unknown',
    touched_areas: ['system', 'scripts', '08_n8n'],
    new_files_count: 0,
    modified_files_count: 0,
    key_files: ['system/memory/STATE_PROJECT.json'],
    blockers: [],
    next_action: 'Revisar resultado manual',
    website_build_exists: false,
    website_article_count: 0
  }
}];

// Validate and enrich checkpoint payload
const body = $input.first().json.body || $input.first().json;

if (!body.event || body.event !== 'checkpoint_generated') {
  throw new Error('Payload inválido: falta event=checkpoint_generated');
}

const ts = body.timestamp || new Date().toISOString();
const date = ts.split('T')[0];

const summary = body.summary || 'Sin resumen';
const gitStatus = body.git_status || 'unknown';
const branch = body.git_branch || 'unknown';
const areas = body.touched_areas || [];
const blockers = body.blockers || [];
const nextAction = body.next_action || '';
const newCount = body.new_files_count || 0;
const modCount = body.modified_files_count || 0;
const keyFiles = body.key_files || [];
const checkpointFile = body.checkpoint_file || '';

// Build Telegram message (for optional use)
const lines = [
  '📡 *Checkpoint FG*',
  '',
  '📅 ' + date,
  '🔀 Repo: ' + gitStatus + ' (' + branch + ')',
  '📁 ' + newCount + ' nuevos, ' + modCount + ' modificados',
  '📂 Áreas: ' + (areas.length > 0 ? areas.join(', ') : 'ninguna'),
];
if (blockers.length > 0) {
  lines.push('');
  lines.push('⚠️ *Bloqueadores:*');
  for (const b of blockers) {
    lines.push('  • ' + b);
  }
}
if (nextAction) {
  lines.push('');
  lines.push('➡️ ' + nextAction);
}
const telegramText = lines.join('\n');

return [{
  json: {
    timestamp: ts,
    date,
    summary,
    gitStatus,
    branch,
    areas,
    blockers,
    nextAction,
    newCount,
    modCount,
    keyFiles,
    checkpointFile,
    telegramText,
    receivedAt: new Date().toISOString()
  }
}];

// Write/append to n8n-side checkpoint log
const fs = require('fs');
const d = $input.first().json;
const logDir = '/workspace/07_Operaciones/logs';

try { fs.mkdirSync(logDir, { recursive: true }); } catch(e) {}

const logFile = logDir + '/n8n_checkpoint_log_' + d.date + '.json';

let entries = [];
try {
  const raw = fs.readFileSync(logFile, 'utf8');
  entries = JSON.parse(raw);
  if (!Array.isArray(entries)) entries = [entries];
} catch(e) {
  entries = [];
}

entries.push({
  received_at: d.receivedAt,
  checkpoint_timestamp: d.timestamp,
  checkpoint_file: d.checkpointFile,
  git_status: d.gitStatus,
  branch: d.branch,
  areas_count: d.areas.length,
  new_files: d.newCount,
  modified_files: d.modCount,
  blockers_count: d.blockers.length,
  next_action: d.nextAction
});

fs.writeFileSync(logFile, JSON.stringify(entries, null, 2), 'utf8');

return [{ json: Object.assign({}, d, { logFile, logWritten: true }) }];
